      "content": "const { randomUUID } = require('node:crypto');

let projects = {};

function getAllProjects() {
  return Object.values(projects);
}

function getProjectById(id) {
  return projects[id] || null;
}

function addProject(name) {
  const id = randomUUID();
  projects[id] = { id, name };
  return projects[id];
}

module.exports = {
  getAllProjects,
  getProjectById,
  addProject
};
