      "content": "let membersByProject = {};

function getMembers(projectId) {
  return membersByProject[projectId] || [];
}

function addMember(projectId, userId, role) {
  if (!membersByProject[projectId]) {
    membersByProject[projectId] = [];
  }
  const member = { userId, role };
  membersByProject[projectId].push(member);
  return member;
}

module.exports = {
  getMembers,
  addMember
};
